/// Generic command handler trait for CQRS pattern
///
/// Implements the handler pattern for CQRS commands.
/// Each command type should have a corresponding handler implementation.
///
/// # Example
/// ```ignore
/// #[async_trait]
/// impl CommandHandler<CreateUserCommand> for CreateUserHandler {
///     type Output = User;
///
///     async fn handle(&self, cmd: CreateUserCommand) -> Result<Self::Output> {
///         // Handle user creation
///     }
/// }
/// ```
#[async_trait]
pub trait CommandHandler<C: Send>: Send + Sync {
    /// The output type produced by handling the command
    type Output: Send;

    /// Handle the command and produce a result
    async fn handle(&self, command: C) -> Result<Self::Output>;
}

/// Command bus for routing commands to their handlers
///
/// Provides a central dispatch mechanism for commands,
/// enabling loose coupling between command producers and handlers.
pub struct CommandBus;

impl CommandBus {
    /// Create a new command bus
    pub fn new() -> Self {
        Self
    }

    /// Dispatch a command to its handler
    pub async fn dispatch<C, H>(&self, handler: &H, command: C) -> Result<H::Output>
    where
        C: Send,
        H: CommandHandler<C>,
    {
        handler.handle(command).await
    }
}

impl Default for CommandBus {
    fn default() -> Self {
        Self::new()
    }
}

